(3, 'koinly', 'Koinly', 'Crypto tax made simple', 'Koinly automagically calculates your crypto taxes and generates IRS-friendly reports in minutes.', 'https://cryptologos.cc/logos/koinly-logo.png', 'https://koinly.io', 'https://koinly.io?ref=CryptoDir', '15% commission', 'Earn 15% commission on all sales. Affiliate dashboard with real-time tracking.', 'subscription', '$49/year', 4.7, 4123, true, true, ARRAY['Auto-syncs with exchanges', 'DeFi & NFT support', 'Multi-country tax reports', 'Free tier available', 'Excellent integrations'], ARRAY['Free tier limited', 'Some edge cases tricky', 'Occasional sync delays']),
(3, 'cointracker', 'CoinTracker', 'Track your crypto in one place', 'CoinTracker offers portfolio tracking and tax calculation with seamless exchange integration.', 'https://cryptologos.cc/logos/cointracker-logo.png', 'https://cointracker.io', 'https://cointracker.io?ref=CryptoDir', '20% commission', 'Earn 20% commission on all subscription referrals. Premium affiliates get additional perks.', 'subscription', '$59/year', 4.5, 3521, true, true, ARRAY['Clean dashboard', 'TurboTax integration', 'Real-time portfolio tracking', 'Coinbase partner'], ARRAY['Tax calculations extra', 'Limited free tier', 'Customer support response times']),
(3, 'crypto-tax-calculator', 'Crypto Tax Calculator', 'Comprehensive crypto tax solution', 'Specialized tax software for complex crypto portfolios including DeFi and staking income.', 'https://cryptologos.cc/logos/crypto-tax-logo.png', 'https://cryptotaxcalculator.io', 'https://cryptotaxcalculator.io?ref=CryptoDir', '20% commission', '20% commission on all plans. Performance bonuses for top affiliates.', 'subscription', '$49/year', 4.6, 2892, false, true, ARRAY['DeFi-focused', 'Complex transaction handling', 'Accountant review feature', 'Audit trail export'], ARRAY['Less known brand', 'UI could be improved', 'Learning curve']),
(3, 'tax-bit', 'TaxBit', 'Enterprise-grade crypto tax', 'TaxBit offers professional-grade tax reporting with direct exchange and broker integrations.', 'https://cryptologos.cc/logos/taxbit-logo.png', 'https://taxbit.com', 'https://taxbit.com?ref=CryptoDir', '15% commission', '15% commission with enterprise-level affiliate support.', 'subscription', '$99/year', 4.4, 1923, false, true, ARRAY['Enterprise features', 'Direct exchange APIs', 'Professional tax forms', 'IRS-ready reports'], ARRAY['Higher pricing', 'Overkill for small portfolios', 'Business-focused features']);